Signature pad.

3 min read
1 hour ago

--

“The Webapp UI Component Series contains many modules with basic webapp functionality and style attributes. The purpose of this Series is to organize Webapp UI Components into a single useful and functional application.”
In this post, a signature pad template is demonstrated. The whiteboard Webapp UI Component was used to make this application.
Version 0: one-stroke
<!DOCTYPE>
<html>
<head></head>
<body>
<div class="javascript_css"></div>
<script>
function div_element(num) {
var divElement = document.createElement("div");
divElement.setAttribute("id", "div"+num);
divElement.setAttribute("class", "div_simple");
divElement.setAttribute("onpointerdown", "processEvent_pointerdown(event)");
divElement.setAttribute("onpointermove", "processEvent_pointermove(event)");
divElement.setAttribute("onpointerup", "processEvent_pointerup(event)");
divElement.style.position = "absolute";
divElement.style.top = "60px";
divElement.style.left = "0px";
divElement.style.width = "300px";
divElement.style.height = "100px";
divElement.style.border = "1px solid lightgray";
divElement.style.borderRadius = "2px";
divElement.style.touchAction = "none"; return divElement;
}
</script>
<script>
function whiteboard(idValue) {
if (document.getElementById(idValue) == null) {
document.getElementsByClassName("javascript_css")[0].appendChild(div_element(0));
document.getElementById(idValue).count = 0;
document.getElementById(idValue).style.top = "60px";
}
}
function processEvent_pointerdown(event) {
var idValue0 = "div0";
document.getElementById(idValue0).arrX = [];
document.getElementById(idValue0).arrY = [];
document.getElementById(idValue0).elasped_time = new Date().getTime();
}
function processEvent_pointermove(event) {
var idValue0 = "div0";
document.getElementById(idValue0).arrX.push(event.offsetX);
document.getElementById(idValue0).arrY.push(event.offsetY);
}
function processEvent_pointerup(event) {
var idValue0 = "div0";
document.getElementById(idValue0).arrX.push(event.offsetX);
document.getElementById(idValue0).arrY.push(event.offsetY);
// count = arrX.length-1;
document.getElementById(idValue0).elasped_time = document.getElementById(idValue0).elasped_time - new Date().getTime();
var gapX = 1;
var radius = 1;
var tot_html_circle_string = "";
for (var i=0; i<document.getElementById(idValue0).arrX.length; i++) {
tot_html_circle_string = tot_html_circle_string + `<circle id="circle${i}" class="circle_simple" cx="${document.getElementById(idValue0).arrX.at(i)*gapX}" cy="${document.getElementById(idValue0).arrY.at(i)}" r="${radius}" fill="rgb(0,0,0)" stroke="rgb(0,0,0)"/>`;
if (i > 0) {
tot_html_circle_string = tot_html_circle_string + `<path id="line${i-1}" class="line_simple" d="M ${document.getElementById(idValue0).arrX.at(i-1)*gapX} ${document.getElementById(idValue0).arrY.at(i-1)} L ${document.getElementById(idValue0).arrX.at(i)*gapX} ${document.getElementById(idValue0).arrY.at(i)}" fill="transparent" stroke="rgb(0,0,0)" stroke-width="3"/>`;
}
}
var html_string = `<svg id="svg0" class="svg_simple" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 300 100">${tot_html_circle_string}</svg>`;
document.getElementById("div0").html_string = html_string;
var url_string = `url('data:image/svg+xml;utf8,${html_string}')`;
document.getElementById(idValue0).style.backgroundImage = url_string;
}
</script>
<script>
function save_copy_img(html_string, idValue) {
var encoded = encodeURIComponent(html_string);
// OR
// var encoded = html_string;
document.getElementById(idValue).src = "data:image/svg+xml," + encoded;
}
</script>
<script>
topbar();
function topbar() {
document.getElementsByClassName("javascript_css")[0].style.position = "absolute";
document.getElementsByClassName("javascript_css")[0].style.width = "300px";
document.getElementsByClassName("javascript_css")[0].style.height = "50px";
document.getElementsByClassName("javascript_css")[0].style.border = "1px solid gray";
document.getElementsByClassName("javascript_css")[0].style.borderRadius = "2px";
document.getElementsByClassName("javascript_css")[0].innerHTML = "Signature pad one-stroke.";
whiteboard();
}
</script>
</body>
</html>
Version 1: multiple strokes
<!DOCTYPE>
<html>
<head></head>
<body>
<div class="javascript_css"></div>
<script>
function div_element(num) {
var divElement = document.createElement("div");
divElement.setAttribute("id", "div"+num);
divElement.setAttribute("class", "div_simple");
divElement.setAttribute("onpointerdown", "processEvent_pointerdown(event)");
divElement.setAttribute("onpointermove", "processEvent_pointermove(event)");
divElement.setAttribute("onpointerup", "processEvent_pointerup(event)");
divElement.style.position = "absolute";
divElement.style.top = "0px";
divElement.style.left = "0px";
divElement.style.width = "300px";
divElement.style.height = "100px";
divElement.style.border = "1px solid lightgray";
divElement.style.borderRadius = "2px";
divElement.style.touchAction = "none"; return divElement;
}
</script>
<script>
function whiteboard(idValue) {
if (document.getElementById(idValue) == null) {
document.getElementsByClassName("javascript_css")[0].appendChild(div_element(0));
document.getElementById(idValue).count = 0;
document.getElementById(idValue).style.top = "60px";
}
}
function processEvent_pointerdown(event) {
var id = event.target.id.split("").map((v,i) => { return (parseInt(v).toString() == "NaN") ? v : undefined; }).filter((v) => v != undefined).join("");
var idValue0 = id+"0";
document.getElementById(idValue0).arrX = [];
document.getElementById(idValue0).arrY = [];
document.getElementById(idValue0).elasped_time = new Date().getTime();
}
function processEvent_pointermove(event) {
var id = event.target.id.split("").map((v,i) => { return (parseInt(v).toString() == "NaN") ? v : undefined; }).filter((v) => v != undefined).join("");
var idValue0 = id+"0";
document.getElementById(idValue0).arrX.push(event.offsetX);
document.getElementById(idValue0).arrY.push(event.offsetY);
}
function processEvent_pointerup(event) {
var id = event.target.id.split("").map((v,i) => { return (parseInt(v).toString() == "NaN") ? v : undefined; }).filter((v) => v != undefined).join("");
var idValue0 = id+"0";
document.getElementById(idValue0).arrX.push(event.offsetX);
document.getElementById(idValue0).arrY.push(event.offsetY);
// count = arrX.length-1;
document.getElementById(idValue0).elasped_time = document.getElementById(idValue0).elasped_time - new Date().getTime();
var gapX = 1;
var radius = 1;
var tot_html_circle_string = "";
for (var i=0; i<document.getElementById(idValue0).arrX.length; i++) {
tot_html_circle_string = tot_html_circle_string + `<circle id="circle${i}" class="circle_simple" cx="${document.getElementById(idValue0).arrX.at(i)*gapX}" cy="${document.getElementById(idValue0).arrY.at(i)}" r="${radius}" fill="rgb(0,0,0)" stroke="rgb(0,0,0)"/>`;
if (i > 0) {
tot_html_circle_string = tot_html_circle_string + `<path id="line${i-1}" class="line_simple" d="M ${document.getElementById(idValue0).arrX.at(i-1)*gapX} ${document.getElementById(idValue0).arrY.at(i-1)} L ${document.getElementById(idValue0).arrX.at(i)*gapX} ${document.getElementById(idValue0).arrY.at(i)}" fill="transparent" stroke="rgb(0,0,0)" stroke-width="3"/>`;
}
}
var html_string = `<svg id="svg0" class="svg_simple" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 300 100">${tot_html_circle_string}</svg>`;
var url_string = `url('data:image/svg+xml;utf8,${html_string}')`;
var count = parseInt(document.getElementById(idValue0).count);
if (document.getElementById(idValue0) != null) {
document.getElementById(idValue0).appendChild(div_element(count));
}
document.getElementById(id+count).style.backgroundImage = url_string;
document.getElementById(idValue0).count = count + 1;
}
</script>
<script>
topbar();
function topbar() {
document.getElementsByClassName("javascript_css")[0].style.position = "absolute";
document.getElementsByClassName("javascript_css")[0].style.width = "300px";
document.getElementsByClassName("javascript_css")[0].style.height = "50px";
document.getElementsByClassName("javascript_css")[0].style.border = "1px solid gray";
document.getElementsByClassName("javascript_css")[0].style.borderRadius = "2px";
document.getElementsByClassName("javascript_css")[0].innerHTML = "Signature pad.";
whiteboard("div0");
}
</script>
</body>
</html>
